   117→// ─── Seed default admin account ──────────────────────────────────────────────
   118→async function seedAdminUser() {
   119→  const adminEmail = (process.env.ADMIN_EMAIL || "").toLowerCase();
   120→  const adminPassword = process.env.ADMIN_PASSWORD || "ipc23771";
   121→  if (!adminEmail) return;
   122→  try {
   123→    const existing = await db.select({ id: usersTable.id }).from(usersTable).where(eq(usersTable.email, adminEmail)).limit(1);
   124→    if (existing.length === 0) {
   125→      const passwordHash = await bcrypt.hash(adminPassword, 12);
   126→      await db.insert(usersTable).values({
   127→        username: "admin",
   128→        email: adminEmail,
   129→        passwordHash,
   130→      });
   131→      console.log(`  ✅ Admin account created: ${adminEmail}`);
   132→    } else {
   133→      console.log(`  ✓  Admin account exists: ${adminEmail}`);
   134→    }
   135→  } catch (err) {
   136→    console.error("  ⚠️  Failed to seed admin account:", err?.message);
   137→  }
   138→}
   139→
   140→// ─── Start ───────────────────────────────────────────────────────────────────
   141→const server = app.listen(PORT, "0.0.0.0", async () => {
   142→  console.log("");
