   144→  console.log(`  ➜  http://localhost:${PORT}`);
   145→  console.log(`  ➜  API: http://localhost:${PORT}/api/healthz`);
   146→  if (!fs.existsSync(distDir)) {
   147→    console.log("");
   148→    console.log("  ⚠️  No /dist folder found. Run: npm run build");
   149→  }
   150→  await seedAdminUser();
   151→  console.log("");
   152→});
   153→
   154→function shutdown(signal) {
   155→  console.log(`\n${signal} — shutting down gracefully...`);
   156→  server.close(() => { console.log("Server closed."); process.exit(0); });
